// SPDX-License-Identifier: MIT
pragma solidity >=0.8.0 <0.9.0;

//Interface toi thieu de xac nhan contract nhan NFT an toan
interface IERC721Received{
    /**
     * @dev Xác nhận việc nhận NFT. Hàm này phải trả về đúng selector 
     * `bytes4(keccak256("onERC721Received(address,address,uint256,bytes)"))`
     */
    function onERC721Received(
        address operator,
        address from,
        uint256 tokenID,
        bytes calldata data
    )  external view returns (bytes4);
}
//@title Property_Certificate_Registry
//@notice moi ban chung nhan quyen so huu = 1 NFT va chuyen nhuong se qua escrow
contract Property_Certificate_Registry{
    //enum la kieu du lieu tu dinh nghia cho 1 gia tri cho 1 thoi diem
    //LeaseStatus la trang thai cua hop dong chuyen nhuong NFT
    enum LeaseStatus {
        None,
        Created,
        Deleted,
        Active,
        Cancelled
    }
    //totalshare = 100 la 100%, vi du nguoi so huu chi co 50 shares la 50% von so huu
    //public cho phep goi ham tu bat cu dau | private chi goi ham trong cung 1 contract
    // constant la tinh chat khong the thay doi
    uint256 public constant totalshare = 100; 
    uint256 public Propertyid=1 ;
    uint256 public Saleid=1 ;
    uint256 public Transfer_Requestid=1 ;
    //platformAdmin la vi deploy contract
    address public platformAdmin; //dia chi vi etherum cua Admin
    //ten va ma cua NFT
    string public name = "Property Certificate Registry"; 
    string public symbol = "PCR";

    //trang thai cua yeu cau chuyen nhuong tai san
    enum TransferStatus {
        None,
        Pending,
        Approved,
        Rejected,
        Cacncelled
    }

    //Property la thong tin ban ghi cho 1 nha/dat
    struct Property{
        uint256 id;
        uint256 certificateTokenId;
        address manager;
        string location;
        string certificateURI;
        string metadataURI;
        bool active;
        bool fractionalized;
        uint256 totalShares;
        uint256 createdAt;
        uint256 updatedAt;
    }

    //CertificateSales luu thong tin giao dich NFT
    struct CertificateSales{
        uint256 id;
        uint256 propertyId;
        uint256 certificateTokenId;
        address seller;
        address buyer;
        string documentHash;
        LeaseStatus status; //lay tu trang thai hop dong o tren
        uint256 createdAt;
        uint256 depositedAt;
        uint256 releasedAt;
        address releasedBy;
    }
    //ShareTransferRequest dung khi chuyen 1 phan von so huu cho nguoi khac bang quyen shares
    struct ShareTransferRequest{
        uint256 id;
        uint256 propertyId;
        address from;
        address to;
        uint256 shares;
        string documentHash;
        TransferStatus status;
        uint256 requestedAt;
        uint256 processedAt;
        address processedBy;
    }
    //cac dia chi co quyen vd nhu Admin/manager website
    mapping(address => bool) public manager;
    //cac mapping de luu property, sale va request theo id
    mapping(uint256 => Property) private properties;
    mapping(uint256 => CertificateSales) private certificatesales;
    mapping(uint256 => ShareTransferRequest) private ShareTransferRequests;
    
    //cac mapping luu active va lich su giao dich cua tung property
    //vd: ID tai san --> value duy nhat dang active
    mapping(uint256 => uint256) public activeSalesProperty;
    //uint256[] la array >< uint256 la simple
    mapping(uint256 => uint256[]) public saleIdsByProperty; //lich su sale
    mapping(uint256 => uint256[]) public shareTransferRequestIdsByProperty; //lich su request
    
    //ownershipShares dung cho dong so huu: propertyId => owner => totalshares
    //luu tru so luong shares cho 1 tai san theo 1 id
    mapping(uint256 => mapping(address => uint256)) private ownershipShares;
    //luu tru nhieu dia chi so huu cho moi id
    mapping(uint256 => address[]) private ownerByProperty;
    // luu tru (True/False) cua dia chi theo id
    mapping(uint256 => mapping(address => bool)) private IsOwnerListed;
    
    //Bo nho: ai so huu token, balance, approval, tokenURL
    //nguoi soo huu token theo dia chi id
    mapping(uint256 => address) private tokenOwners;
    //Balance token (so du cua token)
    mapping(address => uint256) private tokenBalance;
    //approval token (co hop le khong? True/False)
    mapping(address => mapping(address => bool)) private tokenApproval;
    //Token Url (metadataURL)
    mapping(uint256 => string) private tokenUrl; 
}

